solution.javascript:
import { test, expect } from '@playwright/test';

test('fill registration form', async ({ page }) => {
  await page.goto('https://practice.expandtesting.com/form-validation');
  await page.fill('#validationCustom01', 'John Doe');
  await page.fill('#validationCustom05', '1234567890');
  await page.fill('#validationCustom04', '2024-12-31');
  await page.selectOption('#validationCustom03', 'credit-card');
  await page.getByRole('button', { name: 'Register' }).click();
  await expect(page.getByText('Form submitted successfully')).toBeVisible();
});

